# Generated by agint:generate-lab. Edit the scenario/component for lab-specific setup.
from __future__ import annotations

import os
import shlex
from urllib.parse import quote

from invoke.collection import Collection
from invoke.context import Context
from invoke.tasks import task

from tasks.e2e_framework.aws.deploy import deploy
from tasks.e2e_framework.destroy import destroy as e2e_destroy
from tasks.e2e_framework.tool import get_host

SCENARIO_NAME = "aws/kafka"
CHECK_COMMAND = "sudo -u dd-agent datadog-agent check kafka"
REMOTE_HOSTNAME = "agent-host"
SOURCE_URL = "https://github.com/DataDog/integrations-core"
SOURCE_REF = "master"
SOURCE_PATH = "kafka"
DEFAULT_DD_SITE = "ddintdev.datadoghq.com"


def _missing_outputs_message(role: str) -> str:
    return (
        "create did not complete successfully; stack outputs are missing. "
        f"Expected host output for role {role!r}. Check the create failure before running status/check/exec/ssh."
    )


def _ssh_base(ctx: Context, role: str, stack_name: str | None = None) -> str:
    try:
        host = get_host(ctx, role, SCENARIO_NAME, stack_name)
    except KeyError as exc:
        raise RuntimeError(_missing_outputs_message(role)) from exc
    command = f"ssh {host.user}@{host.address}"
    if host.port:
        command += f" -p {host.port}"
    return command


def _run_remote(ctx: Context, role: str, command: str, stack_name: str | None = None):
    if not command:
        raise ValueError("command is required")
    return ctx.run(f"{_ssh_base(ctx, role, stack_name)} -- {shlex.quote(command)}")


def _datadog_site() -> str:
    return os.environ.get("DD_SITE") or os.environ.get("DATADOG_SITE") or DEFAULT_DD_SITE


def _datadog_base_url() -> str:
    site = _datadog_site().removeprefix("https://").removeprefix("http://")
    if site.startswith("app.") or site.startswith("ddintdev."):
        return f"https://{site}"
    return f"https://app.{site}"


def _datadog_host_url(hostname: str) -> str:
    return f"{_datadog_base_url()}/infrastructure?tags=host%3A{quote(hostname)}"


def _best_effort_datadog_hostname(ctx: Context, role: str, stack_name: str | None = None) -> str:
    metadata_command = (
        "token=$(curl -fsS -X PUT http://169.254.169.254/latest/api/token "
        "-H 'X-aws-ec2-metadata-token-ttl-seconds: 60' --max-time 2 2>/dev/null || true); "
        "if [ -n \"$token\" ]; then "
        "curl -fsS -H \"X-aws-ec2-metadata-token: $token\" --max-time 2 "
        "http://169.254.169.254/latest/meta-data/instance-id || hostname -f 2>/dev/null || hostname; "
        "else hostname -f 2>/dev/null || hostname; fi"
    )
    try:
        result = _run_remote(ctx, role, metadata_command, stack_name=stack_name)
        hostname = result.stdout.strip().splitlines()[-1]
        if hostname:
            return hostname
    except Exception:
        pass
    try:
        host = get_host(ctx, role, SCENARIO_NAME, stack_name)
        return host.address
    except Exception:
        return role


def _show_create_success_message(ctx: Context, stack_name: str | None = None, role: str = REMOTE_HOSTNAME) -> None:
    try:
        ssh_command = _ssh_base(ctx, role, stack_name)
        hostname = _best_effort_datadog_hostname(ctx, role, stack_name)
    except Exception as exc:
        print(f"Datadog host URL unavailable until stack outputs exist: {exc}")
        return
    print("\nLab created. Useful links:")
    print(f"  SSH: {ssh_command}")
    print(f"  Datadog host: {_datadog_host_url(hostname)}")
    print(
        "  Note: Whether the host appears depends on the API key configured for this lab, and data may take a minute to arrive.\n"
    )


@task
def create(
    ctx: Context,
    config_path: str | None = None,
    stack_name: str | None = None,
    pipeline_id: str | None = None,
    agent_version: str | None = None,
    debug: bool | None = False,
    agent_flavor: str | None = None,
    agent_config_path: str | None = None,
    local_package: str | None = None,
):
    """Create the integration lab by deploying the E2E scenario and print host inspection links."""
    full_stack_name = deploy(
        ctx,
        SCENARIO_NAME,
        config_path=config_path,
        stack_name=stack_name,
        pipeline_id=pipeline_id,
        install_agent=True,
        agent_version=agent_version,
        debug=debug,
        use_fakeintake=False,
        agent_flavor=agent_flavor,
        agent_config_path=agent_config_path,
        local_package=local_package,
    )
    _show_create_success_message(ctx, stack_name)
    return full_stack_name


@task
def destroy_lab(ctx: Context, config_path: str | None = None, stack_name: str | None = None):
    """Destroy resources owned by this integration lab."""
    return e2e_destroy(ctx, scenario_name=SCENARIO_NAME, config_path=config_path, stack=stack_name)


@task
def status(ctx: Context, role: str = REMOTE_HOSTNAME, stack_name: str | None = None):
    """Run datadog-agent status on the Agent host and return the full output."""
    return _run_remote(ctx, role, "sudo datadog-agent status", stack_name=stack_name)


@task
def check(ctx: Context, role: str = REMOTE_HOSTNAME, stack_name: str | None = None):
    """Run the configured Agent check on the Agent host."""
    return _run_remote(ctx, role, CHECK_COMMAND, stack_name=stack_name)


@task(name="reload-check")
def reload_check(ctx: Context, role: str = REMOTE_HOSTNAME, stack_name: str | None = None):
    """Manually reinstall the declared check source and run configcheck/check."""
    if not SOURCE_URL or not SOURCE_REF or not SOURCE_PATH:
        raise ValueError("source, ref, and source_path are required for reload-check")
    commands = [
        "set -euo pipefail",
        "workdir=$(mktemp -d)",
        "git clone " + shlex.quote(SOURCE_URL) + " $workdir/src",
        "git -C $workdir/src checkout " + shlex.quote(SOURCE_REF),
        "sudo -u dd-agent datadog-agent integration install -r $workdir/src/" + shlex.quote(SOURCE_PATH),
        "sudo systemctl restart datadog-agent || sudo service datadog-agent restart",
        "sudo datadog-agent configcheck",
        CHECK_COMMAND,
    ]
    return _run_remote(ctx, role, " && ".join(commands), stack_name=stack_name)


@task(name="exec")
def exec_(ctx: Context, role: str = REMOTE_HOSTNAME, command: str | None = None, stack_name: str | None = None):
    """Run an explicit command on a lab host role."""
    if command is None:
        raise ValueError("--command is required")
    return _run_remote(ctx, role, command, stack_name=stack_name)


@task
def ssh(ctx: Context, role: str = REMOTE_HOSTNAME, stack_name: str | None = None, connect: bool = False):
    """Print or open SSH access for a lab host role."""
    command = _ssh_base(ctx, role, stack_name)
    print(command)
    if connect:
        return ctx.run(command, pty=True)
    return None


collection = Collection("kafka")
collection.add_task(create)
collection.add_task(destroy_lab, name="destroy")
collection.add_task(status)
collection.add_task(check)
collection.add_task(reload_check, name="reload-check")
collection.add_task(exec_)
collection.add_task(ssh)
